// Load target companies config
const fs = require('fs');
const path = process.env.TARGET_COMPANIES_PATH || '/Users/YOURNAME/Projects/job-scraper/config/target_companies.json';
const config = JSON.parse(fs.readFileSync(path, 'utf8'));
const active = config.companies.filter(c => c.active);
return active.map(c => ({ json: c }));

// Fetch job listings from official careers page via HTTP
// This is the primary source of truth — aggregators are supplemental only.
const company = $input.item.json;
const axios = require('axios');

let jobs = [];
let crawlStatus = 'success';
let errorDetail = null;

try {
  const response = await axios.get(company.careers_url, {
    timeout: 15000,
    headers: {
      'User-Agent': 'Mozilla/5.0 (compatible; JobScraperBot/1.0; research)'
    }
  });

  // NOTE: Each ATS platform requires a custom parser.
  // The Code node below (ATS Parser) handles platform-specific extraction.
  // This node just fetches the raw page/API response.
  jobs = [{
    raw_html: response.data,
    status_code: response.status,
    company_id: company.company_id,
    ats_platform: company.ats_platform,
    careers_url: company.careers_url
  }];
} catch (err) {
  const msg = err.message || '';
  if (msg.includes('captcha') || msg.includes('403') || msg.includes('429')) {
    crawlStatus = 'captcha_blocked';
  } else if (msg.includes('401') || msg.includes('auth')) {
    crawlStatus = 'auth_expired';
  } else {
    crawlStatus = 'failed';
  }
  errorDetail = msg;
  jobs = [];
}

return [{
  json: {
    company,
    jobs,
    crawl_status: crawlStatus,
    error_detail: errorDetail,
    crawled_at: new Date().toISOString()
  }
}];

// ATS-specific job extraction.
// Each platform exposes job data differently.
// Extend this switch as new ATS platforms are encountered.

const { company, jobs, crawled_at } = $input.item.json;
const rawHtml = jobs[0]?.raw_html || '';
const platform = company.ats_platform;
let extracted = [];

switch (platform) {
  case 'greenhouse': {
    // Greenhouse JSON feed: careers_url typically ends in /jobs
    // Try to parse as JSON first (Greenhouse board API)
    try {
      const data = JSON.parse(rawHtml);
      const jobList = data.jobs || data.positions || [];
      extracted = jobList.map(j => ({
        title: j.title,
        location: j.location?.name || '',
        url: j.absolute_url || j.url || '',
        posting_id: String(j.id || ''),
        description: j.content || '',
        company_id: company.company_id
      }));
    } catch {
      // fallback: HTML scraping (set selector_error)
      extracted = [];
    }
    break;
  }
  case 'lever': {
    try {
      const data = JSON.parse(rawHtml);
      const postings = Array.isArray(data) ? data : (data.postings || []);
      extracted = postings.map(p => ({
        title: p.text || p.title || '',
        location: p.categories?.location || p.workplaceType || '',
        url: p.hostedUrl || p.applyUrl || '',
        posting_id: p.id || '',
        description: p.descriptionPlain || p.description || '',
        company_id: company.company_id
      }));
    } catch {
      extracted = [];
    }
    break;
  }
  case 'workday': {
    // Workday uses a JS-rendered page; HTML scraping required.
    // Flag for browser automation sidecar.
    extracted = [{ _needs_browser: true, company_id: company.company_id }];
    break;
  }
  default: {
    // Generic HTML — flag for selector-based extraction.
    extracted = [{ _needs_browser: true, company_id: company.company_id }];
  }
}

return extracted.map(j => ({
  json: { ...j, crawled_at, source: 'careers_page', company }
}));

// Log crawl error and emit alert payload
const { company, crawl_status, error_detail, crawled_at } = $input.item.json;

const alertType = {
  'captcha_blocked': 'CAPTCHA_BLOCKED',
  'auth_expired': 'AUTH_EXPIRED',
  'selector_error': 'SELECTOR_BROKEN',
  'failed': 'SELECTOR_BROKEN'
}[crawl_status] || 'SELECTOR_BROKEN';

return [{
  json: {
    alert_type: alertType,
    company_id: company.company_id,
    source_url: company.careers_url,
    detail: `Crawl failed for ${company.display_name}: ${error_detail}`,
    created_at: new Date().toISOString()
  }
}];
